// tb_capture_basic — scope_core full-depth capture vs the Python golden reference (issue #4).
//
// Two scope_core instances (PROBE_W=32/DEPTH_LOG2=8 with sample_valid gaps, and
// PROBE_W=512/DEPTH_LOG2=10 back-to-back) each run one force-triggered capture:
//   * stimulus is read from the .mem files generated by sim/model/scope_ref.py (invoked by
//     sim/run.sh; the address-seeded xorshift pattern is the hyperram_bw_test.sv trick);
//   * arm with pretrig=0, windows=1; trig pulsed for one cycle while presenting sample
//     index DEPTH/2 (the force_trig poke);
//   * after DONE: full buffer readback via the read port compared word-by-word against the
//     model's _buf.mem — while fresh poisoned samples keep streaming, proving the write
//     pointer does not advance in DONE;
//   * trig_index / wrapped / windows_done / triggered / armed checked against _meta.mem;
//   * ts_at_trig checked against the ts value observed in the trigger cycle;
//   * observed state sequence must be exactly IDLE -> FILLING -> ARMED -> TRIGGERED -> DONE.
// Self-checking: $fatal (prints "TB_RESULT: FAIL") on mismatch; "TB_RESULT: PASS" on success.
`timescale 1ns / 1ps

/* verilator lint_off DECLFILENAME */
// waiver: helper module deliberately co-located in its TB's file (not a standalone unit)
module tb_capture_leg
  import scope_pkg::*;
#(
    parameter int unsigned PROBE_W     = 32,
    parameter int unsigned DEPTH_LOG2  = 8,
    parameter int unsigned TRIG_SAMPLE = 128,   // sample index (from arm) carrying trig
    parameter int unsigned N_STIM      = 640,   // lines in the stimulus file
    parameter string       VEC_PREFIX  = "",    // run.sh-generated vector path prefix
    parameter bit          GAPS        = 1'b0,  // insert sample_valid gaps
    parameter string       NAME        = "leg"
) (
    output bit done
);

  localparam int unsigned DEPTH = 1 << DEPTH_LOG2;
  localparam int unsigned TS_W = 48;

  logic clk = 1'b0;
  always #5 clk <= ~clk;

  logic                  rst = 1'b1;
  logic [PROBE_W-1:0]    sample_data = '0;
  logic                  sample_valid = 1'b0;
  logic                  trig = 1'b0;
  logic                  arm = 1'b0;
  logic                  disarm = 1'b0;
  logic [DEPTH_LOG2-1:0] pretrig = '0;
  logic [7:0]            windows = 8'd1;
  logic [2:0]            state;
  logic                  triggered;
  logic                  wrapped;
  logic [7:0]            windows_done;
  logic [DEPTH_LOG2-1:0] trig_index;
  logic                  armed;
  logic [DEPTH_LOG2-1:0] rd_addr = '0;
  logic [PROBE_W-1:0]    rd_data;
  logic [TS_W-1:0]       ts;
  logic [TS_W-1:0]       ts_at_trig;
  logic [7:0]            win_rd_addr = 8'h0;
  logic [DEPTH_LOG2:0]   win_rd_data;
  wire unused_win_meta = &{1'b0, win_rd_data};

  scope_core #(
      .PROBE_W   (PROBE_W),
      .DEPTH_LOG2(DEPTH_LOG2),
      .TS_W      (TS_W)
  ) dut (.*);

  // golden vectors from scope_ref.py
  logic [PROBE_W-1:0] stim[N_STIM];
  logic [PROBE_W-1:0] exp_buf[DEPTH];
  logic [63:0]        exp_meta[3];  // 0: trig_index, 1: wrapped, 2: samples consumed
  initial begin
    $readmemh({VEC_PREFIX, "_stim.mem"}, stim);
    $readmemh({VEC_PREFIX, "_buf.mem"}, exp_buf);
    $readmemh({VEC_PREFIX, "_meta.mem"}, exp_meta);
  end

  task automatic fail(input string msg);
    $display("TB_RESULT: FAIL");
    $fatal(1, "[%s] %s", NAME, msg);
  endtask

  // state-sequence monitor: record every state change after reset
  logic [2:0] seq[$];
  logic [2:0] prev_state;
  always @(posedge clk) begin
    if (rst) begin
      prev_state <= 3'(SCOPE_ST_IDLE);
    end else begin
      if (state != prev_state) seq.push_back(state);
      prev_state <= state;
    end
  end

  // ts_at_trig cross-check: capture the ts value in the accepted-trigger cycle
  logic [TS_W-1:0] ts_seen = '0;
  always @(posedge clk) begin
    if (trig && sample_valid && state == 3'(SCOPE_ST_ARMED)) ts_seen <= ts;
  end

  int unsigned idx = 0, cyc = 0;

  initial begin
    repeat (5) @(negedge clk);
    rst = 1'b0;
    @(negedge clk);
    if (state != 3'(SCOPE_ST_IDLE)) fail("not IDLE after reset");

    // arm (pretrig=0, windows=1) and wait for ARMED (pretrig=0 => 1 cycle of FILLING)
    arm = 1'b1;
    @(negedge clk);
    arm = 1'b0;
    while (state != 3'(SCOPE_ST_ARMED)) @(negedge clk);

    // stream samples; trig rides sample index TRIG_SAMPLE
    while (state != 3'(SCOPE_ST_DONE)) begin
      automatic bit v = !(GAPS && (cyc % 5 == 4) && (idx != TRIG_SAMPLE));
      sample_valid = v;
      sample_data  = (idx < N_STIM) ? stim[idx] : ~stim[idx % N_STIM];
      trig         = v && (idx == TRIG_SAMPLE);
      @(negedge clk);
      if (v) idx++;
      cyc++;
    end
    trig = 1'b0;

    // capture-complete status checks
    if (triggered !== 1'b1) fail("triggered not set at DONE");
    if (wrapped !== exp_meta[1][0]) fail("wrapped mismatch vs model");
    if (trig_index !== DEPTH_LOG2'(exp_meta[0]))
      fail($sformatf("trig_index %0d != model %0d", trig_index, exp_meta[0]));
    if (windows_done !== 8'd1) fail("windows_done != 1");
    if (armed !== 1'b0) fail("armed still set in DONE");
    if (ts_at_trig !== ts_seen)
      fail($sformatf("ts_at_trig %0d != ts in trigger cycle %0d", ts_at_trig, ts_seen));

    // full-buffer readback vs model, while poisoned samples keep streaming (write pointer
    // must not advance in DONE — any spurious write corrupts the compare)
    sample_valid = 1'b1;
    for (int unsigned a = 0; a < DEPTH; a++) begin
      rd_addr     = DEPTH_LOG2'(a);
      sample_data = ~stim[a % N_STIM] ^ PROBE_W'(cyc);
      @(negedge clk);
      @(negedge clk);
      if (rd_data !== exp_buf[a])
        fail($sformatf("buffer[%0d] = %h != model %h", a, rd_data, exp_buf[a]));
      cyc++;
    end
    sample_valid = 1'b0;

    // exact state sequence
    if (seq.size() != 4) fail($sformatf("saw %0d state changes, want 4", seq.size()));
    if (seq[0] != 3'(SCOPE_ST_FILLING) || seq[1] != 3'(SCOPE_ST_ARMED) ||
        seq[2] != 3'(SCOPE_ST_TRIGGERED) || seq[3] != 3'(SCOPE_ST_DONE))
      fail("state sequence != IDLE->FILLING->ARMED->TRIGGERED->DONE");

    $display("-- [%s] capture bit-exact vs model: %0d words, trig_index=%0d, wrapped=%b",
             NAME, DEPTH, trig_index, wrapped);
    done = 1'b1;
  end

endmodule
/* verilator lint_on DECLFILENAME */

module tb_capture_basic;

  bit done_a, done_b;

  tb_capture_leg #(
      .PROBE_W    (32),
      .DEPTH_LOG2 (8),
      .TRIG_SAMPLE(128),
      .N_STIM     (640),
      .VEC_PREFIX ("sim/build/vectors/cap_w32_d8"),
      .GAPS       (1'b1),
      .NAME       ("w32_d8_gaps")
  ) leg_a (
      .done(done_a)
  );

  tb_capture_leg #(
      .PROBE_W    (512),
      .DEPTH_LOG2 (10),
      .TRIG_SAMPLE(512),
      .N_STIM     (2560),
      .VEC_PREFIX ("sim/build/vectors/cap_w512_d10"),
      .GAPS       (1'b0),
      .NAME       ("w512_d10")
  ) leg_b (
      .done(done_b)
  );

  initial begin
    wait (done_a && done_b);
    $display("TB_RESULT: PASS");
    $finish;
  end

  initial begin
    #10ms;
    $display("TB_RESULT: FAIL");
    $fatal(1, "timeout: done=%b%b", done_a, done_b);
  end

endmodule
